    const policy = makePolicy([{ type: 'sword', material: 'dragon', enchantment: 9, cursed: false }]);
    const result = processClaim(policy, [
      { itemType: 'sword', amount: 1000 },
    ]);
    expect(result.payout).toBe(400);
