  const policyByStepIndex = new Map<number, Policy>();
  let quoteCount = 0;

  for (let stepIdx = 0; stepIdx < scenario.steps.length; stepIdx++) {
    const step = scenario.steps[stepIdx];
    if (step.op === 'quote') {
      // Validate items
      for (const item of step.items) {
