      const insuranceSum = computeInsuranceSum(step.items);
      const policy: Policy = {
        items: step.items,
        insuranceSum,
        cap: insuranceSum * 2,
        totalPaidOut: 0,
      };
      policyByStepIndex.set(stepIdx, policy);
      quoteCount++;
      results.push({ premium });
    } else if (step.op === 'claim') {
      const refIndex = step.policy;
